if (stripos($version, 'mariadb') !== false) {
    $mariaDbVersion = $this->getMariaDbMysqlVersionNumber($version);
    if (version_compare($mariaDbVersion, '11.7.0', '>=')) {
        return new MariaDB110700Platform();
    }

    if (version_compare($mariaDbVersion, '10.10.0', '>=')) {
        return new MariaDB1010Platform();
    }

    if (version_compare($mariaDbVersion, '10.6.0', '>=')) {
        return new MariaDB1060Platform();
    }

    Deprecation::trigger(
        'doctrine/dbal',
        'https://github.com/doctrine/dbal/pull/6343',
        'Support for MariaDB < 10.6.0 is deprecated and will be removed in DBAL 5',
    );

    if (version_compare($mariaDbVersion, '10.5.2', '>=')) {
        return new MariaDB1052Platform();
    }

    return new MariaDBPlatform();
}

if (isset($options['force_ip_resolve']) && !\filter_var($uri->getHost(), \FILTER_VALIDATE_IP)) {
    if ('v4' === $options['force_ip_resolve']) {
        $records = \dns_get_record($uri->getHost(), \DNS_A);
        if (false === $records || !isset($records[0]['ip'])) {
            throw new ConnectException(\sprintf("Could not resolve IPv4 address for host '%s'", $uri->getHost()), $request);
        }

        return $uri->withHost($records[0]['ip']);
    }
    if ('v6' === $options['force_ip_resolve']) {
        $records = \dns_get_record($uri->getHost(), \DNS_AAAA);
        if (false === $records || !isset($records[0]['ipv6'])) {
            throw new ConnectException(\sprintf("Could not resolve IPv6 address for host '%s'", $uri->getHost()), $request);
        }

        return $uri->withHost('['.$records[0]['ipv6'].']');
    }
}

if (
	$lastCondExpr instanceof BinaryOp\Smaller
	&& $lastCondExpr->left instanceof Variable
	&& $lastCondExpr->right instanceof FuncCall
	&& $lastCondExpr->right->name instanceof Name
	&& !$lastCondExpr->right->isFirstClassCallable()
	&& in_array($lastCondExpr->right->name->toLowerString(), ['count', 'sizeof'], true)
	&& count($lastCondExpr->right->getArgs()) > 0
	&& $lastCondExpr->right->getArgs()[0]->value instanceof Variable
	&& is_string($stmt->init[0]->var->name)
	&& $stmt->init[0]->var->name === $stmt->loop[0]->var->name
	&& $stmt->init[0]->var->name === $lastCondExpr->left->name
) {
	$arrayArg = $lastCondExpr->right->getArgs()[0]->value;
	$arrayType = $bodyScope->getType($arrayArg);
	if ($arrayType->isList()->yes()) {
		$bodyScope = $bodyScope->assignExpression(
			new ArrayDimFetch($lastCondExpr->right->getArgs()[0]->value, $lastCondExpr->left),
			$arrayType->getIterableValueType(),
			$bodyScope->getNativeType($arrayArg)->getIterableValueType(),
		);
	}
}

if (
	$lastCondExpr instanceof BinaryOp\Greater
	&& $lastCondExpr->right instanceof Variable
	&& $lastCondExpr->left instanceof FuncCall
	&& $lastCondExpr->left->name instanceof Name
	&& !$lastCondExpr->left->isFirstClassCallable()
	&& in_array($lastCondExpr->left->name->toLowerString(), ['count', 'sizeof'], true)
	&& count($lastCondExpr->left->getArgs()) > 0
	&& $lastCondExpr->left->getArgs()[0]->value instanceof Variable
	&& is_string($stmt->init[0]->var->name)
	&& $stmt->init[0]->var->name === $stmt->loop[0]->var->name
	&& $stmt->init[0]->var->name === $lastCondExpr->right->name
) {
	$arrayArg = $lastCondExpr->left->getArgs()[0]->value;
	$arrayType = $bodyScope->getType($arrayArg);
	if ($arrayType->isList()->yes()) {
		$bodyScope = $bodyScope->assignExpression(
			new ArrayDimFetch($lastCondExpr->left->getArgs()[0]->value, $lastCondExpr->right),
			$arrayType->getIterableValueType(),
			$bodyScope->getNativeType($arrayArg)->getIterableValueType(),
		);
	}
}

if ($reflection instanceof ReflectionClass || $reflection instanceof ReflectionFunction || $reflection instanceof ReflectionConstant) {
	$fileName = $reflection->getFileName();
	if ($fileName !== null) {
		$normalized = str_replace('\\', '/', $fileName);
		if (str_contains($normalized, '/symfony/polyfill-php80/') && $this->phpVersion->getVersionId() >= 80000) {
			return null;
		}
		if (str_contains($normalized, '/symfony/polyfill-php81/') && $this->phpVersion->getVersionId() >= 80100) {
			return null;
		}
		if (str_contains($normalized, '/symfony/polyfill-php82/') && $this->phpVersion->getVersionId() >= 80200) {
			return null;
		}
		if (str_contains($normalized, '/symfony/polyfill-php83/') && $this->phpVersion->getVersionId() >= 80300) {
			return null;
		}
		if (str_contains($normalized, '/symfony/polyfill-php84/') && $this->phpVersion->getVersionId() >= 80400) {
			return null;
		}
		if (str_contains($normalized, '/symfony/polyfill-php85/') && $this->phpVersion->getVersionId() >= 80500) {
			return null;
		}
	}
}

foreach (explode("\n", substr($doc, 3, -2)) as $line) {
    $line = ltrim($line);
    $line = ltrim($line, '*');

    if ('' === $line = trim($line)) {
        if ('' !== $tagName) {
            $tags[$tagName][] = $tagContent;
        }
        $tagName = $tagContent = '';
        continue;
    }

    if ('@' === $line[0]) {
        if ('' !== $tagName) {
            $tags[$tagName][] = $tagContent;
            $tagContent = '';
        }

        if (preg_match('{^@([-a-zA-Z0-9_:]++)(\s|$)}', $line, $m)) {
            $tagName = $m[1];
            $tagContent = str_replace("\t", ' ', ltrim(substr($line, 2 + \strlen($tagName))));
        } else {
            $tagName = '';
        }
    } elseif ('' !== $tagName) {
        $tagContent .= ' '.str_replace("\t", ' ', $line);
    }
}

foreach ($args as $key => $item) {
    if ('object' === $item[0]) {
        $formattedValue = \sprintf('<em>object</em>(%s)', $this->abbrClass($item[1]));
    } elseif ('array' === $item[0]) {
        $formattedValue = \sprintf('<em>array</em>(%s)', \is_array($item[1]) ? $this->formatArgs($item[1]) : $item[1]);
    } elseif ('null' === $item[0]) {
        $formattedValue = '<em>null</em>';
    } elseif ('boolean' === $item[0]) {
        $formattedValue = '<em>'.strtolower(var_export($item[1], true)).'</em>';
    } elseif ('resource' === $item[0]) {
        $formattedValue = '<em>resource</em>';
    } elseif (preg_match('/[^\x07-\x0D\x1B\x20-\xFF]/', $item[1])) {
        $formattedValue = '<em>binary string</em>';
    } else {
        $formattedValue = str_replace("\n", '', $this->escape(var_export($item[1], true)));
    }

    $result[] = \is_int($key) ? $formattedValue : \sprintf("'%s' => %s", $this->escape($key), $formattedValue);
}

foreach ($this->getLogs()->getValue() as $rawLog) {
    $rawLogData = $rawLog->getValue();

    if ($rawLogData['priority']->getValue() > 300) {
        $logType = 'error';
    } elseif (isset($rawLogData['scream']) && false === $rawLogData['scream']->getValue()) {
        $logType = 'deprecation';
    } elseif (isset($rawLogData['scream']) && true === $rawLogData['scream']->getValue()) {
        $logType = 'silenced';
    } else {
        $logType = 'regular';
    }

    $logs[] = [
        'type' => $logType,
        'errorCount' => $rawLog['errorCount'] ?? 1,
        'timestamp' => $rawLogData['timestamp_rfc3339']->getValue(),
        'priority' => $rawLogData['priority']->getValue(),
        'priorityName' => $rawLogData['priorityName']->getValue(),
        'channel' => $rawLogData['channel']->getValue(),
        'message' => $rawLogData['message'],
        'context' => $rawLogData['context'],
    ];
}

foreach ($email->getAttachments() as $attachment) {
    $headers = $attachment->getPreparedHeaders();

    $contentType = $headers->get('Content-Type')->getBody();
    $base64 = 'text/plain' !== $contentType;
    $disposition = $headers->getHeaderBody('Content-Disposition');

    if ($base64) {
        $body = base64_encode($attachment->getBody());
    } else {
        $body = $attachment->getBody();
    }

    $att = [
        'content_type' => $headers->get('Content-Type')->getBody(),
        'file_name' => $attachment->getFilename(),
        'data' => $body,
        'base64' => $base64,
    ];

    if ($attachment->hasContentId()) {
        $att['content_id'] = $attachment->getContentId();
    } elseif ('inline' === $disposition) {
        $att['content_id'] = $attachment->getFilename();
    }

    $attachments[] = $att;
}
